{"content":"use crate::api::*;
use crate::distance::l2_distance;
use rayon::prelude::*;
use std::cmp::Ordering;
use std::collections::BinaryHeap;
use std::sync::RwLock;

const DIM: usize = 128;

pub struct VectorDB {
    inner: RwLock<DBInner>,
}

struct DBInner {
    ids: Vec<u64>,
    vectors: Vec<f32>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            inner: RwLock::new(DBInner {
                ids: Vec::new(),
                vectors: Vec::new(),
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        if vector.len() != DIM {
            return;
        }
        let mut inner = self.inner.write().unwrap();
        inner.ids.push(id);
        inner.vectors.extend_from_slice(&vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut inner = self.inner.write().unwrap();
        let mut inserted = 0;
        inner.ids.reserve(vectors.len());
        inner.vectors.reserve(vectors.len() * DIM);
        for (id, vector) in vectors {
            if vector.len() != DIM {
                continue;
            }
            inner.ids.push(id);
            inner.vectors.extend_from_slice(&vector);
            inserted += 1;
        }
        inserted
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let k = top_k as usize;
        if k == 0 || vector.len() != DIM {
            return Vec::new();
        }
        let inner = self.inner.read().unwrap();
        let total = inner.ids.len();
        if total == 0 {
            return Vec::new();
        }
        let heap = inner
            .vectors
            .par_chunks_exact(DIM)
            .enumerate()
            .fold(
                || BinaryHeap::with_capacity(k + 1),
                |mut heap, (idx, v)| {
                    let dist = l2_distance(vector, v);
                    let item = HeapItem {
                        dist,
                        id: inner.ids[idx],
                    };
                    push_with_limit(&mut heap, item, k);
                    heap
                },
            )
            .reduce(
                || BinaryHeap::with_capacity(k + 1),
                |mut a, b| {
                    for item in b.into_iter() {
                        push_with_limit(&mut a, item, k);
                    }
                    a
                },
            );

        let mut results: Vec<SearchResult> = heap
            .into_vec()
            .into_iter()
            .map(|item| SearchResult {
                id: item.id,
                distance: item.dist as f64,
            })
            .collect();
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
        results
    }
}

fn push_with_limit(heap: &mut BinaryHeap<HeapItem>, item: HeapItem, k: usize) {
    if heap.len() < k {
        heap.push(item);
    } else if let Some(top) = heap.peek() {
        if item.dist < top.dist {
            heap.pop();
            heap.push(item);
        }
    }
}

#[derive(Debug, Clone, Copy)]
struct HeapItem {
    dist: f32,
    id: u64,
}

impl Eq for HeapItem {}

impl PartialEq for HeapItem {
    fn eq(&self, other: &Self) -> bool {
        self.dist == other.dist && self.id == other.id
    }
}

impl Ord for HeapItem {
    fn cmp(&self, other: &Self) -> Ordering {
        self.dist
            .partial_cmp(&other.dist)
            .unwrap_or(Ordering::Equal)
    }
}

impl PartialOrd for HeapItem {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}
