        Self {
            inner: RwLock::new(DBInner {
                ids: Vec::new(),
                vectors: Vec::new(),
            }),
            dist_impl: select_distance_impl(),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        if vector.len() != DIM {
            return;
        }
        let mut inner = self.inner.write();
        inner.ids.push(id);
        inner.vectors.extend_from_slice(&vector);
    }

